import React from "react";

const alertStyle = {
  position: "fixed",
  top: "20px",
  right: "20px",
  backgroundColor: "#ff4d4f",
  color: "white",
  padding: "10px 20px",
  borderRadius: "5px",
  boxShadow: "0 2px 5px rgba(0,0,0,0.3)",
  zIndex: 1000,
};

const Alert = ({ message }) => {
  if (!message) return null;

  return <div style={alertStyle}>{message}</div>;
};

export default Alert;
